1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
15	
16	const sumBasePremiums = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
18	
19	const computePremium = (items: Item[]): number => {
20	  const base = sumBasePremiums(items);
21	  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
22	  return withFirstInsurance + PROCESSING_FEE;
23	};
24	
25	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
26	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
27	const roundUpToGold = (amount: number): number =>
28	  Math.ceil(Math.round(amount * 1e6) / 1e6);
29	
30	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
31	  const results = scenario.steps.map((step) => ({
32	    premium: roundUpToGold(computePremium(step.items)),
33	  }));
34	  return { results };
35	};
